import { streamText } from 'ai';
import { z } from 'zod';

const detectPII = (text: string) => {
  const emailRegex = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g;
  const phoneRegex = /\(?(\d{3})\)?[-.\s]?(\d{3})[-.\s]?(\d{4})/g;
  return {
    hasEmail: emailRegex.test(text),
    hasPhone: phoneRegex.test(text),
    matches: [...text.match(emailRegex) || [], ...text.match(phoneRegex) || []]
  };
};

const result = await streamText({
  model: openai('gpt-4o-mini'),
  onFinish: ({ text }) => {
    const pii = detectPII(text);
    if (pii.hasEmail || pii.hasPhone) {
      console.error('PII detected:', pii.matches);
    }
  }
});

for await (const chunk of result.textStream) {
  const pii = detectPII(chunk);
  if (pii.hasEmail || pii.hasPhone) {
    console.warn('Streaming PII detected:', pii.matches);
  }
}

import { generateObject } from 'ai';
