import { streamUI } from 'ai/rsc';
import { messageHistory } from './chat-history';

const scanHistoryPII = (messages: any[]) => {
  return messages.some(msg => 
    /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/.test(msg.content)
  );
};

const ui = await streamUI({
  model: openai('gpt-4o'),
  messages: messageHistory,
  beforeGenerate: () => {
    if (scanHistoryPII(messageHistory)) {
      console.error('PII found in conversation history');
      return { error: 'Conversation contains sensitive data' };
    }
  }
});

